import sys
from collections import deque

class Solution:
    def isValidDequeue(self, n, queue, k):
        queue = deque(queue)
        if k < 0 or k >= n:
            return False
        if queue[k] == 0:
            return True
        return False

if __name__ == '__main__':
    n = int(input())
    for _ in range(n):
        queue = list(map(int, input().split()))
        k = int(input())
        solution = Solution()
        print(solution.isValidDequeue(n, queue, k))

