#include <iostream>
#include <algorithm>
#include <vector>

using namespace std;

class Solution {
public:
    bool isValidDequeue(int n, int queue[], int k) {
        if (k < 0 || k >= n) return false;
        if (queue[k] == 0) return true;
        return false;
    }
};

int main() {
    int n;
    cin >> n;
    for (int i = 0; i < n; i++) {
        for (int i = 0; i < n; i++) cin >> queue[i];
        int k;
        cin >> k;
        Solution solution;
        cout << (solution.isValidDequeue(n, queue, k) ? "True" : "False") << endl;
    }
    return 0;
}
